### Issue 5: TTL Archiver Missing Failure Handling (SRE)

**Problem**: V3 S3 write failure = permanent data loss.

**Solution**: DLQ + retry + dead letter notification.

```typescript
// TTL Archiver with comprehensive error handling
const archiveHandler = async (event: DynamoDBStreamEvent): Promise<SQSBatchResponse> => {
  const batchItemFailures: SQSBatchItemFailure[] = [];

  for (const record of event.Records) {
    try {
      if (record.eventName !== 'REMOVE' ||
          record.userIdentity?.principalId !== 'dynamodb.amazonaws.com') {
        continue;
      }

      const oldImage = unmarshall(record.dynamodb!.OldImage!);

      // Validate required fields exist
      if (!oldImage.cpf_token || !oldImage.cpf_encrypted) {
        logger.error('Invalid record structure', { record_id: record.eventID });
        // Don't retry invalid records, but log for investigation
        await publishToDeadLetterTopic({
          type: 'INVALID_RECORD_STRUCTURE',
          record_id: record.eventID,
          timestamp: new Date().toISOString()
        });
        continue;
      }

      const archiveRecord = {
        cpf_token: oldImage.cpf_token,
        cpf_encrypted: oldImage.cpf_encrypted,
        created_at: oldImage.created_at,
        resolved_at: oldImage.status === 'RESOLVED' ? oldImage.last_retry_at : null,
        final_status: oldImage.status,
        error_codes: [oldImage.error_code],
        total_retry_count: oldImage.total_retry_count || 0,
        archived_at: new Date().toISOString(),
        archive_version: '1.0'
      };

      // Write to S3 with explicit error handling
      await writeToS3WithRetry(archiveRecord, {
        maxRetries: 3,
        retryDelayMs: 1000
      });

      logger.info('Record archived successfully', {
        cpf_token: archiveRecord.cpf_token,
        created_at: archiveRecord.created_at
      });

    } catch (error) {
      logger.error('Failed to archive record', {
        error: (error as Error).message,
        record_id: record.eventID
      });

      // Add to batch failures for SQS retry
      batchItemFailures.push({
        itemIdentifier: record.eventID!
      });
    }
  }

  return { batchItemFailures };
};

const writeToS3WithRetry = async (
  record: ArchiveRecord,
  options: { maxRetries: number; retryDelayMs: number }
): Promise<void> => {
  const key = generateArchiveKey(record);

  for (let attempt = 1; attempt <= options.maxRetries; attempt++) {
    try {
      await s3Client.send(new PutObjectCommand({
        Bucket: process.env.ARCHIVE_BUCKET!,
        Key: key,
        Body: JSON.stringify(record),
        ContentType: 'application/json',
        ServerSideEncryption: 'aws:kms',
        SSEKMSKeyId: process.env.KMS_KEY_ARN!,
        Metadata: {
          'cpf-token': record.cpf_token,
          'archive-version': record.archive_version
        }
      }));
      return;
    } catch (error) {
      if (attempt === options.maxRetries) {
        throw error;
      }
      await sleep(options.retryDelayMs * attempt);
    }
  }
};

const generateArchiveKey = (record: ArchiveRecord): string => {
  const date = new Date(record.created_at);
  return `archives/year=${date.getFullYear()}/month=${String(date.getMonth() + 1).padStart(2, '0')}/` +
         `day=${String(date.getDate()).padStart(2, '0')}/${record.cpf_token}.json`;
};

const publishToDeadLetterTopic = async (failure: object): Promise<void> => {
  await snsClient.send(new PublishCommand({
    TopicArn: process.env.ARCHIVE_DLQ_TOPIC_ARN!,
    Message: JSON.stringify(failure),
    Subject: 'TTL Archiver Failure'
  }));
};
```

