### Issue 3: Salt Storage Vulnerability (Security)

**Problem**: V3 SSM salt without versioning; if modified, existing cpf_tokens become orphaned.

**Solution**: Versioned salt format `v1:hash` with migration path.

```typescript
// Salt versioning implementation
interface VersionedSalt {
  version: number;
  value: string;
  createdAt: string;
  status: 'ACTIVE' | 'DEPRECATED' | 'RETIRED';
}

interface CpfToken {
  token: string;        // Full versioned token: "v1:sha256hash"
  version: number;      // Extracted version for queries
}

const CURRENT_SALT_VERSION = 1;

const getSaltVersions = async (): Promise<Map<number, VersionedSalt>> => {
  const parameter = await ssmClient.send(new GetParameterCommand({
    Name: `/fee-exemption/${process.env.ENVIRONMENT}/salts`,
    WithDecryption: true
  }));

  // Format: {"versions": [{"version": 1, "value": "...", "status": "ACTIVE"}, ...]}
  const salts = JSON.parse(parameter.Parameter!.Value!);
  return new Map(salts.versions.map((s: VersionedSalt) => [s.version, s]));
};

const tokenizeCpf = (cpf: string, saltVersion: number = CURRENT_SALT_VERSION): CpfToken => {
  const salts = await getSaltVersions();
  const salt = salts.get(saltVersion);

  if (!salt || salt.status === 'RETIRED') {
    throw new Error(`Salt version ${saltVersion} not available`);
  }

  const hash = crypto
    .createHmac('sha256', salt.value)
    .update(cpf)
    .digest('hex');

  return {
    token: `v${saltVersion}:${hash}`,
    version: saltVersion
  };
};

const lookupCpfToken = async (cpf: string): Promise<CpfToken[]> => {
  // Look up across all active and deprecated salt versions
  const salts = await getSaltVersions();
  const tokens: CpfToken[] = [];

  for (const [version, salt] of salts) {
    if (salt.status !== 'RETIRED') {
      const hash = crypto
        .createHmac('sha256', salt.value)
        .update(cpf)
        .digest('hex');
      tokens.push({ token: `v${version}:${hash}`, version });
    }
  }

  return tokens;
};

// DynamoDB schema update - add salt_version attribute
interface FailureRecord {
  cpf_token: string;       // PK: "v1:abc123..."
  salt_version: number;    // For query optimization
  cpf_encrypted: string;
  // ... other fields
}
```

**SSM Parameter Format**:

```json
{
  "versions": [
    {
      "version": 1,
      "value": "base64-encoded-salt-here",
      "createdAt": "2026-02-04T00:00:00Z",
      "status": "ACTIVE"
    }
  ],
  "currentVersion": 1
}
```

**Salt Rotation Runbook (RB-011)**:

```markdown
## Salt Rotation Procedure

### When to Rotate
- Suspected salt compromise
- Annual rotation policy (optional)
- Compliance requirement

### Steps

1. **Add new salt version** (DO NOT remove old salt)
   ```bash
   # Get current salts
   CURRENT=$(aws ssm get-parameter --name /fee-exemption/prod/salts --with-decryption --query 'Parameter.Value' --output text)

   # Add new version
   NEW_SALT=$(openssl rand -base64 32)
   NEW_VERSION=$(echo "$CURRENT" | jq '.currentVersion + 1')

   UPDATED=$(echo "$CURRENT" | jq --arg salt "$NEW_SALT" --arg version "$NEW_VERSION" '
     .versions += [{"version": ($version | tonumber), "value": $salt, "createdAt": (now | todate), "status": "ACTIVE"}] |
     .currentVersion = ($version | tonumber)
   ')

   aws ssm put-parameter --name /fee-exemption/prod/salts --value "$UPDATED" --type SecureString --overwrite
   ```

2. **Deprecate old salt version**
   ```bash
   UPDATED=$(aws ssm get-parameter --name /fee-exemption/prod/salts --with-decryption --query 'Parameter.Value' --output text | \
     jq '.versions |= map(if .version == 1 then .status = "DEPRECATED" else . end)')
   aws ssm put-parameter --name /fee-exemption/prod/salts --value "$UPDATED" --type SecureString --overwrite
   ```

3. **Retire old salt** (only after all records migrated or expired)
   - Wait for TTL to expire all v1 records
   - Verify no queries for v1 tokens in logs
   - Update status to RETIRED

### Rollback
- If issues occur, revert SSM parameter to previous version
- Old tokens remain valid as long as salt exists
```

### Issue 4: Circuit Breaker State Persistence (SRE)

**Problem**: V3 Lambda is stateless; SSM has race conditions and latency for circuit breaker.

**Solution**: DynamoDB-backed circuit breaker with atomic operations.

```typescript
// Circuit breaker state stored in dedicated DynamoDB table
interface CircuitBreakerState {
  service_id: string;           // PK: "CBILL"
  state: 'CLOSED' | 'OPEN' | 'HALF_OPEN';
  failure_count: number;
  success_count: number;        // For HALF_OPEN recovery
  last_failure_at: string | null;
  last_success_at: string | null;
  opened_at: string | null;
  version: number;              // Optimistic locking
  ttl: number;                  // Auto-reset after 1 hour
}

const CIRCUIT_BREAKER_CONFIG = {
  failureThreshold: 5,          // Open after 5 consecutive failures
  successThreshold: 3,          // Close after 3 consecutive successes in HALF_OPEN
  openDurationMs: 60000,        // Stay open for 1 minute
  halfOpenRequests: 3           // Allow 3 test requests in HALF_OPEN
};

class DynamoCircuitBreaker {
  private tableName: string;
  private serviceId: string;

  constructor(tableName: string, serviceId: string) {
    this.tableName = tableName;
    this.serviceId = serviceId;
  }

  async getState(): Promise<CircuitBreakerState> {
    const result = await dynamoClient.send(new GetCommand({
      TableName: this.tableName,
      Key: { service_id: this.serviceId }
    }));

    if (!result.Item) {
      // Initialize with CLOSED state
      return this.initializeState();
    }

    const state = result.Item as CircuitBreakerState;

    // Check if OPEN state has expired
    if (state.state === 'OPEN' && state.opened_at) {
      const openedAt = new Date(state.opened_at).getTime();
      if (Date.now() - openedAt >= CIRCUIT_BREAKER_CONFIG.openDurationMs) {
        return this.transitionTo('HALF_OPEN', state);
      }
    }

    return state;
  }

  async recordSuccess(): Promise<CircuitBreakerState> {
    const current = await this.getState();

    if (current.state === 'CLOSED') {
      return current; // No change needed
    }

    if (current.state === 'HALF_OPEN') {
      const newSuccessCount = current.success_count + 1;
      if (newSuccessCount >= CIRCUIT_BREAKER_CONFIG.successThreshold) {
        return this.transitionTo('CLOSED', current);
      }

      // Increment success count
      return this.updateSuccessCount(current, newSuccessCount);
    }

    return current;
  }

  async recordFailure(error: Error): Promise<CircuitBreakerState> {
    const current = await this.getState();

    if (current.state === 'OPEN') {
      return current; // Already open, ignore
    }

    const newFailureCount = current.failure_count + 1;

    if (current.state === 'HALF_OPEN' ||
        newFailureCount >= CIRCUIT_BREAKER_CONFIG.failureThreshold) {
      return this.transitionTo('OPEN', current);
    }

    return this.updateFailureCount(current, newFailureCount);
  }

  async canExecute(): Promise<boolean> {
    const state = await this.getState();

    if (state.state === 'CLOSED') return true;
    if (state.state === 'OPEN') return false;

    // HALF_OPEN: allow limited requests
    // Use atomic counter to limit concurrent test requests
    try {
      await dynamoClient.send(new UpdateCommand({
        TableName: this.tableName,
        Key: { service_id: this.serviceId },
        UpdateExpression: 'SET half_open_requests = if_not_exists(half_open_requests, :zero) + :one',
        ConditionExpression: 'half_open_requests < :max',
        ExpressionAttributeValues: {
          ':zero': 0,
          ':one': 1,
          ':max': CIRCUIT_BREAKER_CONFIG.halfOpenRequests
        }
      }));
      return true;
    } catch (err) {
      if ((err as Error).name === 'ConditionalCheckFailedException') {
        return false;
      }
      throw err;
    }
  }

  private async transitionTo(
    newState: 'CLOSED' | 'OPEN' | 'HALF_OPEN',
    current: CircuitBreakerState
  ): Promise<CircuitBreakerState> {
    const now = new Date().toISOString();

    const update = await dynamoClient.send(new UpdateCommand({
      TableName: this.tableName,
      Key: { service_id: this.serviceId },
      UpdateExpression: `
        SET #state = :newState,
            failure_count = :zero,
            success_count = :zero,
            half_open_requests = :zero,
            opened_at = :openedAt,
            last_transition_at = :now,
            version = version + :one,
            #ttl = :ttl
      `,
      ConditionExpression: 'version = :currentVersion',
      ExpressionAttributeNames: {
        '#state': 'state',
        '#ttl': 'ttl'
      },
      ExpressionAttributeValues: {
        ':newState': newState,
        ':zero': 0,
        ':openedAt': newState === 'OPEN' ? now : null,
        ':now': now,
        ':one': 1,
        ':currentVersion': current.version,
        ':ttl': Math.floor(Date.now() / 1000) + 3600 // 1 hour TTL
      },
      ReturnValues: 'ALL_NEW'
    }));

    // Emit metric for state transition
    await cloudwatch.send(new PutMetricDataCommand({
      Namespace: 'FeeExemption/CircuitBreaker',
      MetricData: [{
        MetricName: 'StateTransition',
        Dimensions: [
          { Name: 'ServiceId', Value: this.serviceId },
          { Name: 'FromState', Value: current.state },
          { Name: 'ToState', Value: newState }
        ],
        Value: 1,
        Unit: 'Count'
      }]
    }));

    return update.Attributes as CircuitBreakerState;
  }

  private async initializeState(): Promise<CircuitBreakerState> {
    const initialState: CircuitBreakerState = {
      service_id: this.serviceId,
      state: 'CLOSED',
      failure_count: 0,
      success_count: 0,
      last_failure_at: null,
      last_success_at: null,
      opened_at: null,
      version: 1,
      ttl: Math.floor(Date.now() / 1000) + 3600
    };

    await dynamoClient.send(new PutCommand({
      TableName: this.tableName,
      Item: initialState,
      ConditionExpression: 'attribute_not_exists(service_id)'
    }));

    return initialState;
  }
}
```

