### Issue 5: TTL Archiver Missing Failure Handling (SRE)

**Problem**: V3 S3 write failure = permanent data loss.

**Solution**: DLQ + retry + dead letter notification.

```typescript
// TTL Archiver with comprehensive error handling
const archiveHandler = async (event: DynamoDBStreamEvent): Promise<SQSBatchResponse> => {
  const batchItemFailures: SQSBatchItemFailure[] = [];

  for (const record of event.Records) {
    try {
      if (record.eventName !== 'REMOVE' ||
          record.userIdentity?.principalId !== 'dynamodb.amazonaws.com') {
        continue;
      }

      const oldImage = unmarshall(record.dynamodb!.OldImage!);

      // Validate required fields exist
      if (!oldImage.cpf_token || !oldImage.cpf_encrypted) {
        logger.error('Invalid record structure', { record_id: record.eventID });
        // Don't retry invalid records, but log for investigation
        await publishToDeadLetterTopic({
          type: 'INVALID_RECORD_STRUCTURE',
          record_id: record.eventID,
          timestamp: new Date().toISOString()
        });
        continue;
      }

      const archiveRecord = {
        cpf_token: oldImage.cpf_token,
        cpf_encrypted: oldImage.cpf_encrypted,
        created_at: oldImage.created_at,
        resolved_at: oldImage.status === 'RESOLVED' ? oldImage.last_retry_at : null,
        final_status: oldImage.status,
        error_codes: [oldImage.error_code],
        total_retry_count: oldImage.total_retry_count || 0,
        archived_at: new Date().toISOString(),
        archive_version: '1.0'
      };

      // Write to S3 with explicit error handling
      await writeToS3WithRetry(archiveRecord, {
        maxRetries: 3,
        retryDelayMs: 1000
      });

      logger.info('Record archived successfully', {
        cpf_token: archiveRecord.cpf_token,
        created_at: archiveRecord.created_at
      });

    } catch (error) {
      logger.error('Failed to archive record', {
        error: (error as Error).message,
        record_id: record.eventID
      });

      // Add to batch failures for SQS retry
      batchItemFailures.push({
        itemIdentifier: record.eventID!
      });
    }
  }

  return { batchItemFailures };
};

const writeToS3WithRetry = async (
  record: ArchiveRecord,
  options: { maxRetries: number; retryDelayMs: number }
): Promise<void> => {
  const key = generateArchiveKey(record);

  for (let attempt = 1; attempt <= options.maxRetries; attempt++) {
    try {
      await s3Client.send(new PutObjectCommand({
        Bucket: process.env.ARCHIVE_BUCKET!,
        Key: key,
        Body: JSON.stringify(record),
        ContentType: 'application/json',
        ServerSideEncryption: 'aws:kms',
        SSEKMSKeyId: process.env.KMS_KEY_ARN!,
        Metadata: {
          'cpf-token': record.cpf_token,
          'archive-version': record.archive_version
        }
      }));
      return;
    } catch (error) {
      if (attempt === options.maxRetries) {
        throw error;
      }
      await sleep(options.retryDelayMs * attempt);
    }
  }
};

const generateArchiveKey = (record: ArchiveRecord): string => {
  const date = new Date(record.created_at);
  return `archives/year=${date.getFullYear()}/month=${String(date.getMonth() + 1).padStart(2, '0')}/` +
         `day=${String(date.getDate()).padStart(2, '0')}/${record.cpf_token}.json`;
};

const publishToDeadLetterTopic = async (failure: object): Promise<void> => {
  await snsClient.send(new PublishCommand({
    TopicArn: process.env.ARCHIVE_DLQ_TOPIC_ARN!,
    Message: JSON.stringify(failure),
    Subject: 'TTL Archiver Failure'
  }));
};
```

**Infrastructure for Archiver DLQ**:

```yaml
TTLArchiverDLQ:
  Type: AWS::SQS::Queue
  Properties:
    QueueName: !Sub 'fee-exemption-ttl-archiver-dlq-${Environment}'
    MessageRetentionPeriod: 1209600  # 14 days
    KmsMasterKeyId: !Ref FeeExemptionKMSKey

TTLArchiverDLQAlarm:
  Type: AWS::CloudWatch::Alarm
  Properties:
    AlarmName: !Sub 'fee-exemption-ttl-archiver-dlq-messages-${Environment}'
    AlarmDescription: TTL Archiver has failed messages - potential data loss
    MetricName: ApproximateNumberOfMessagesVisible
    Namespace: AWS/SQS
    Dimensions:
      - Name: QueueName
        Value: !GetAtt TTLArchiverDLQ.QueueName
    Statistic: Sum
    Period: 300
    EvaluationPeriods: 1
    Threshold: 1
    ComparisonOperator: GreaterThanOrEqualToThreshold
    TreatMissingData: notBreaching
    AlarmActions:
      - !Ref CriticalAlertsTopic

ArchiveFailuresTopic:
  Type: AWS::SNS::Topic
  Properties:
    TopicName: !Sub 'fee-exemption-archive-failures-${Environment}'
    KmsMasterKeyId: !Ref FeeExemptionKMSKey
```

### Issue 6: Durability SLO Impractical (SRE)

**Problem**: V3's 99.999% durability at ~1000 writes/month means 1 lost record exhausts annual budget.

**Solution**: Revised SLOs aligned with actual volume and risk tolerance.

```yaml
# Revised SLO Framework

| SLO | Target | Rationale |
|-----|--------|-----------|
| **Availability** | 99.9% | Unchanged - reasonable for internal service |
| **Data Durability** | 99.9% | Realistic: 1 lost record per 1000 (1/month budget) |
| **Replay Latency** | p95 < 10 min | Relaxed from 5 min - adequate for 48h resolution SLA |
| **Time to Resolution** | < 48 hours | Unchanged |
| **Successful Replay Rate** | > 95% | Relaxed from 98% - accounts for CBILL issues |

# Error Budget Calculations (Monthly)

| SLO | Budget | Practical Meaning |
|-----|--------|-------------------|
| Availability | 43.8 min downtime | ~2 short outages |
| Durability | 1 lost record | Acceptable given archive fallback |
| Replay Latency | 5% > 10 min | ~50 slow replays |
| Resolution | 5% > 48h | ~50 delayed resolutions |
| Replay Success | 5% failures | ~50 failed replays |
```

### Issue 7: Global Tables Over-Engineering (Architecture)

**Problem**: Global Tables cost $1.25/month + 2x writes for 500 records/month with 48h SLA.

**Solution**: Single-region with S3 cross-region backup (simpler, cheaper, adequate).

**Decision Matrix**:

| Factor | Global Tables | S3 Cross-Region Backup |
|--------|---------------|------------------------|
| RPO | < 1 minute | < 15 minutes |
| RTO | < 5 minutes | < 30 minutes |
| Cost | ~$1.25/month extra | ~$0.10/month extra |
| Complexity | Higher (multi-region writes) | Lower (read replicas only) |
| Processing Continuity | Yes (if CBILL multi-region) | Data preservation only |

**Recommendation**: **Remove Global Tables** unless:
1. Compliance mandates multi-region data residency, OR
2. CBILL has multi-region endpoints

**Simplified DR Architecture**:

```
┌─────────────────────────────────────────────────────────────────┐
│                    PRIMARY REGION (sa-east-1)                   │
│                                                                 │
│  ┌──────────────┐    ┌─────────────────────┐                   │
│  │ DLQ-Consumer │───▶│ DynamoDB            │                   │
│  │ Lambda       │    │ fee_exemption_      │                   │
│  └──────────────┘    │ failures            │                   │
│                      └──────────┬──────────┘                   │
│                                 │                               │
│                    DynamoDB Streams                            │
│                                 │                               │
│                                 ▼                               │
│                      ┌──────────────────────┐                   │
│                      │ S3 Backup Lambda     │                   │
│                      │ (Real-time export)   │                   │
│                      └──────────┬───────────┘                   │
│                                 │                               │
└─────────────────────────────────┼───────────────────────────────┘
                                  │
                    S3 Cross-Region Replication
                                  │
┌─────────────────────────────────┼───────────────────────────────┐
│                                 ▼                               │
│                    SECONDARY REGION (us-east-1)                 │
│                                                                 │
│                      ┌──────────────────────┐                   │
│                      │ S3 Backup Bucket     │                   │
│                      │ (Read-only replica)  │                   │
│                      └──────────────────────┘                   │
│                                                                 │
│                    For DR: Restore to new DynamoDB table        │
│                                                                 │
└─────────────────────────────────────────────────────────────────┘
```

### Issue 8: WAF Disproportionate (Architecture)

**Problem**: $5.50/month WAF for ~200 internal requests; private API reduces need.

**Solution**: Remove WAF for private VPC-only API. Rely on:
- VPC endpoint with security group restrictions
- API Gateway resource policies
- IAM authentication
- Rate limiting at API Gateway level

```yaml
# API Gateway without WAF (private API)
FeeExemptionAPI:
  Type: AWS::ApiGateway::RestApi
  Properties:
    Name: !Sub 'fee-exemption-api-${Environment}'
    EndpointConfiguration:
      Types:
        - PRIVATE
      VpcEndpointIds:
        - !Ref APIGatewayVPCEndpoint

    # Resource policy restricts to VPC
    Policy:
      Version: '2012-10-17'
      Statement:
        - Effect: Deny
          Principal: '*'
          Action: execute-api:Invoke
          Resource: !Sub 'arn:aws:execute-api:${AWS::Region}:${AWS::AccountId}:*/*/*/*'
          Condition:
            StringNotEquals:
              'aws:SourceVpce': !Ref APIGatewayVPCEndpoint
        - Effect: Allow
          Principal: '*'
          Action: execute-api:Invoke
          Resource: !Sub 'arn:aws:execute-api:${AWS::Region}:${AWS::AccountId}:*/*/*/*'

# Rate limiting via usage plan
APIUsagePlan:
  Type: AWS::ApiGateway::UsagePlan
  Properties:
    UsagePlanName: !Sub 'fee-exemption-standard-${Environment}'
    Throttle:
      BurstLimit: 50
      RateLimit: 10
    Quota:
      Limit: 1000
      Period: DAY
```

