## Health Check Lambda Specification

```typescript
interface HealthCheckResponse {
  status: 'healthy' | 'degraded' | 'unhealthy';
  timestamp: string;
  components: {
    dynamodb: ComponentHealth;
    sqs: ComponentHealth;
    cbill: ComponentHealth;
    circuitBreaker: CircuitBreakerHealth;
  };
  metrics: {
    pendingRetryCount: number;
    inProgressCount: number;
    lastHourFailures: number;
  };
}

interface ComponentHealth {
  status: 'healthy' | 'unhealthy';
  latencyMs: number;
  message?: string;
}

interface CircuitBreakerHealth {
  status: 'healthy' | 'warning' | 'critical';
  state: 'CLOSED' | 'OPEN' | 'HALF_OPEN';
  failureCount: number;
}

const healthCheckHandler = async (): Promise<APIGatewayProxyResult> => {
  const startTime = Date.now();
  const components: HealthCheckResponse['components'] = {
    dynamodb: await checkDynamoDB(),
    sqs: await checkSQS(),
    cbill: await checkCBILL(),
    circuitBreaker: await checkCircuitBreaker()
  };

  const metrics = await getHealthMetrics();

  const overallStatus = determineOverallStatus(components, metrics);

  const response: HealthCheckResponse = {
    status: overallStatus,
    timestamp: new Date().toISOString(),
    components,
    metrics
  };

  return {
    statusCode: overallStatus === 'healthy' ? 200 : overallStatus === 'degraded' ? 200 : 503,
    body: JSON.stringify(response),
    headers: {
      'Content-Type': 'application/json',
      'Cache-Control': 'no-cache'
    }
  };
};

const checkDynamoDB = async (): Promise<ComponentHealth> => {
  const start = Date.now();
  try {
    await dynamoClient.send(new DescribeTableCommand({
      TableName: process.env.DYNAMODB_TABLE!
    }));
    return {
      status: 'healthy',
      latencyMs: Date.now() - start
    };
  } catch (error) {
    return {
      status: 'unhealthy',
      latencyMs: Date.now() - start,
      message: (error as Error).message
    };
  }
};

const checkSQS = async (): Promise<ComponentHealth> => {
  const start = Date.now();
  try {
    await sqsClient.send(new GetQueueAttributesCommand({
      QueueUrl: process.env.MAIN_QUEUE_URL!,
      AttributeNames: ['ApproximateNumberOfMessages']
    }));
    return {
      status: 'healthy',
      latencyMs: Date.now() - start
    };
  } catch (error) {
    return {
      status: 'unhealthy',
      latencyMs: Date.now() - start,
      message: (error as Error).message
    };
  }
};

const checkCBILL = async (): Promise<ComponentHealth> => {
  const start = Date.now();
  // Lightweight GraphQL introspection query
  try {
    const response = await graphqlClient.query({
      query: '{ __typename }'
    });
    return {
      status: 'healthy',
      latencyMs: Date.now() - start
    };
  } catch (error) {
    return {
      status: 'unhealthy',
      latencyMs: Date.now() - start,
      message: (error as Error).message
    };
  }
};

const checkCircuitBreaker = async (): Promise<CircuitBreakerHealth> => {
  const cb = new DynamoCircuitBreaker(
    process.env.CIRCUIT_BREAKER_TABLE!,
    'CBILL'
  );
  const state = await cb.getState();

  return {
    status: state.state === 'CLOSED' ? 'healthy' :
            state.state === 'HALF_OPEN' ? 'warning' : 'critical',
    state: state.state,
    failureCount: state.failure_count
  };
};

const getHealthMetrics = async (): Promise<HealthCheckResponse['metrics']> => {
  // Query DynamoDB for current counts
  const [pendingResult, inProgressResult] = await Promise.all([
    dynamoClient.send(new QueryCommand({
      TableName: process.env.DYNAMODB_TABLE!,
      IndexName: 'status-created_at-index',
      KeyConditionExpression: 'status_shard = :status',
      ExpressionAttributeValues: { ':status': 'PENDING_RETRY#0' },
      Select: 'COUNT'
    })),
    dynamoClient.send(new QueryCommand({
      TableName: process.env.DYNAMODB_TABLE!,
      IndexName: 'status-created_at-index',
      KeyConditionExpression: 'status_shard = :status',
      ExpressionAttributeValues: { ':status': 'IN_PROGRESS#0' },
      Select: 'COUNT'
    }))
  ]);

  return {
    pendingRetryCount: pendingResult.Count || 0,
    inProgressCount: inProgressResult.Count || 0,
    lastHourFailures: await getLastHourFailureCount()
  };
};
```

