### Issue 3: Salt Storage Vulnerability (Security)

**Problem**: V3 SSM salt without versioning; if modified, existing cpf_tokens become orphaned.

**Solution**: Versioned salt format `v1:hash` with migration path.

```typescript
// Salt versioning implementation
interface VersionedSalt {
  version: number;
  value: string;
  createdAt: string;
  status: 'ACTIVE' | 'DEPRECATED' | 'RETIRED';
}

interface CpfToken {
  token: string;        // Full versioned token: "v1:sha256hash"
  version: number;      // Extracted version for queries
}

const CURRENT_SALT_VERSION = 1;

const getSaltVersions = async (): Promise<Map<number, VersionedSalt>> => {
  const parameter = await ssmClient.send(new GetParameterCommand({
    Name: `/fee-exemption/${process.env.ENVIRONMENT}/salts`,
    WithDecryption: true
  }));

  // Format: {"versions": [{"version": 1, "value": "...", "status": "ACTIVE"}, ...]}
  const salts = JSON.parse(parameter.Parameter!.Value!);
  return new Map(salts.versions.map((s: VersionedSalt) => [s.version, s]));
};

const tokenizeCpf = async (cpf: string, saltVersion: number = CURRENT_SALT_VERSION): Promise<CpfToken> => {
  const salts = await getSaltVersions();
  const salt = salts.get(saltVersion);

  if (!salt || salt.status === 'RETIRED') {
    throw new Error(`Salt version ${saltVersion} not available`);
  }

  const hash = crypto
    .createHmac('sha256', salt.value)
    .update(cpf)
    .digest('hex');

  return {
    token: `v${saltVersion}:${hash}`,
    version: saltVersion
  };
};

const lookupCpfToken = async (cpf: string): Promise<CpfToken[]> => {
  // Look up across all active and deprecated salt versions
  const salts = await getSaltVersions();
  const tokens: CpfToken[] = [];

  for (const [version, salt] of salts) {
    if (salt.status !== 'RETIRED') {
      const hash = crypto
        .createHmac('sha256', salt.value)
        .update(cpf)
        .digest('hex');
      tokens.push({ token: `v${version}:${hash}`, version });
    }
  }

  return tokens;
};

// DynamoDB schema update - add salt_version attribute
interface FailureRecord {
